using LEGAL.Shared.Helpers;using Serilog;
EnvLoader.Load();Log.Logger=new LoggerConfiguration().MinimumLevel.Information().WriteTo.Console().WriteTo.File("logs/ai-.log",rollingInterval:RollingInterval.Day,retainedFileCountLimit:30).CreateLogger();
try{Log.Information("LEGAL Ai starting on port 5227...");var b=WebApplication.CreateBuilder(args);b.Host.UseSerilog();b.Services.AddControllers();b.Services.AddEndpointsApiExplorer();b.Services.AddSwaggerGen(c=>{c.SwaggerDoc("v1",new(){Title="LEGAL Ai",Version="v1"});});b.Services.AddHealthChecks();b.Services.AddCors(o=>o.AddDefaultPolicy(p=>p.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader()));var app=b.Build();app.UseSerilogRequestLogging();app.UseCors();if(app.Environment.IsDevelopment()){app.UseSwagger();app.UseSwaggerUI();}app.MapControllers();app.MapHealthChecks("/api/health");app.Run();}catch(Exception ex){Log.Fatal(ex,"LEGAL Ai terminated");}finally{Log.CloseAndFlush();}
